#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100000
#define MAX_K 100000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int A[N], D[N], B[K];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &D[i]);
        }
        for (int i = 0; i < K; i++) {
            scanf("%d", &B[i]);
        }
        int cards[N * MAX_N];
        int card_count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < D[i]; j++) {
                cards[card_count++] = A[i];
            }
        }
        for (int i = 0; i < K; i++) {
            qsort(cards, card_count, sizeof(int), compare);
            int sum = 0;
            for (int j = card_count - B[i]; j < card_count; j++) {
                sum += cards[j];
            }
            card_count -= (card_count - B[i]);
        }
        printf("%d\n", cards[card_count - 1]);
    }
    return 0;
}

