        for (int i = 0; i < N; i++) {
            for (int j = 0; j < D[i]; j++) {
                pq.push(A[i]);
            }
        }
        for (int i = 0; i < K; i++) {
            vector<int> temp;
            for (int j = 0; j < B[i]; j++) {
                temp.push_back(pq.top());
                pq.pop();
            }
            for (int j = 0; j < B[i]; j++) {
                pq.push(temp[j]);
            }
        }
        int sum = 0;
        for (int i = 0; i < B[K - 1]; i++) {
            sum += pq.top();
            pq.pop();
        }
        cout << sum << endl;
    }
    return 0;
}

