import java.util.PriorityQueue;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            int[] D = new int[N];
            int[] B = new int[K];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                D[i] = sc.nextInt();
            }
            for (int i = 0; i < K; i++) {
                B[i] = sc.nextInt();
            }
            PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> b - a);
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < D[i]; j++) {
                    pq.add(A[i]);
                }
            }
            for (int i = 0; i < K; i++) {
                int[] temp = new int[B[i]];
                for (int j = 0; j < B[i]; j++) {
                    temp[j] = pq.poll();
                }
                for (int j = 0; j < B[i]; j++) {
                    pq.add(temp[j]);
                }
            }
            int sum = 0;
            for (int i = 0; i < B[K - 1]; i++) {
                sum += pq.poll();
            }
            System.out.println(sum);
        }
    }
}

